import React, {useState, useRef} from 'react'
import { formatCardNumber } from '../../store/Util';


export default function BoxImagePreview(props) {
  
  let crdNm = props.crdNm || "XXXXXXXX";
  let _type = props.type || "bpa";
  
  const [editCNmb, setEditCNmb] = useState(false);
  const [editName, setEditName] = useState(false);
  const [isValid, setIsValid] = useState(false);


  const cardNumberRef = useRef("")
  const cardNameRef = useRef("")

  const updCardNumber = () =>{
    setEditCNmb(1)
    setTimeout(()=>{
      cardNumberRef.current.value = props.crdNm?props.crdNm.split("").slice(8,16).join(""):"";
      if(  typeof props.updCardNumber === "function"){
        props.updCardNumber("");
        setIsValid(false)
      }
    },15)
  }



  const handleKey = (e) =>{
    if(isValid && e.keyCode===13){
      setEditCNmb(0)
      if(  typeof props.updCardNumber === "function"){
        let newValue = props.cardStart+""+cardNumberRef.current.value;
        props.updCardNumber(newValue);
        setIsValid(false)
      }
    }
  }


  const handleChange = (e) =>{
    let v = cardNumberRef.current.value;
    if(v.toString().length===8){
      setIsValid(true)
    }else{
      setIsValid(false)
    }
  }


  
  const handleKeyName = (e) =>{
    if(e.keyCode===13){
      setEditName(0)
      if(  typeof props.updCardName === "function"){
        props.updCardName(cardNameRef.current.value);
      }
    }
  }

  const updCardName = () =>{
    setEditName(1)
    setTimeout(()=>{
      cardNameRef.current.value = props.crdName;
    },5)
  }

  return (
    <div className={`cardViewer ${_type}`}>
      <div className="oDySvb e7E2gc" style={cards[_type]["style2"]}>
        {_type==="metropolitano"?
        <div className="ap5GNb" style={cards[_type]["style3"]}>
          <div className="mtrpl _dsplFlx">
            <img 
              src={cards[_type]["logo"]}
              className="" 
              alt=""
              style={cards[_type]["style"]}
            />
            <p>
              Banco Metropolitano
            </p>
          </div>
        </div>
        :
        <div className="ap5GNb" style={cards[_type]["style3"]}>
          <img 
            src={cards[_type]["logo"]}
            className="Ws3Esf" 
            alt=""
            style={cards[_type]["style"]}
          />
        </div>}
        <div className={`infoCustomer `}>
          {!crdNm || editCNmb?
          <div className={`cardNumber _dsplFlx ${isValid?"":"error"}`}>
            <span>{formatCardNumber(props.cardStart)}</span> 
            <input ref={cardNumberRef} type={"number"} className={` `} onKeyDown={handleKey} onChange={handleChange}/>
          </div>:
          <div className={`cardNumber `} onClick={updCardNumber}>
            {formatCardNumber(props.crdNm?props.crdNm:props.cardStart+""+crdNm)} 
          </div>
          }
          {editName?
          <div className={`cardName editName`}>
            <input ref={cardNameRef} type={"text"}  onKeyDown={handleKeyName} placeholder={"Nombre y Apellidos"}/>
          </div>
          :<div className={`cardName `}  onClick={updCardName}>
            <p>{props.crdName?props.crdName:"Nombre y Apellidos"}</p> 
          </div>}
        </div>
      </div>
    </div>
  )
}



const cards={
  "bpa":{
    "logo": "https://qvamarkets.com/getImagesRzx/LOGO_BPA_PNG_600.webp",
    "numbers": ["92251299","92351299"],
    "style": {height:'26px', margin:'10px'},
    "style2":{ width:"240px", padding:0},
    "style3":{height:'50px', width:"140px", margin: "10px 0 0 10px"}
  },
  "bandec":{
    "logo": "https://qvamarkets.com/getImagesRzx/bandec_white.webp",
    "numbers": ["92250699","92350699"],
    "style": {height:'40px', margin:'10px'},
    "style2":{ width:"240px", padding:0 ,backgroundImage:" linear-gradient(to right, firebrick, rgba(255,0,0,.51),firebrick)" },
    "style3":{height:'50px', width:"140px", margin: "10px 0 0 10px"}
  },
  "metropolitano":{
    "logo":"https://qvamarkets.com/getImagesRzx/metropolitano.webp",
    "numbers":["92259598","92359598"],
    "style": {height:'40px', margin:'10px'},
    "style2":{ width:"240px", padding:0},
    "style3":{height:'50px', width:"210px", margin: " 0 "}
  },
}






